CREATE PROCEDURE liq_drop_training_week_fk()
BEGIN
    DECLARE v_fk VARCHAR(255) DEFAULT NULL;
    SELECT CONSTRAINT_NAME INTO v_fk
    FROM information_schema.KEY_COLUMN_USAGE
    WHERE TABLE_SCHEMA = DATABASE()
      AND TABLE_NAME = 'trainings'
      AND COLUMN_NAME = 'training_week_id'
      AND REFERENCED_TABLE_NAME IS NOT NULL
    LIMIT 1;
    IF v_fk IS NOT NULL THEN
        SET @drop_sql = CONCAT('ALTER TABLE trainings DROP FOREIGN KEY `', v_fk, '`');
        PREPARE drop_stmt FROM @drop_sql;
        EXECUTE drop_stmt;
        DEALLOCATE PREPARE drop_stmt;
    END IF;
END//

CREATE PROCEDURE liq_drop_training_weeks_comp_fk()
BEGIN
    DECLARE v_fk VARCHAR(255) DEFAULT NULL;
    SELECT CONSTRAINT_NAME INTO v_fk
    FROM information_schema.KEY_COLUMN_USAGE
    WHERE TABLE_SCHEMA = DATABASE()
      AND TABLE_NAME = 'training_weeks'
      AND COLUMN_NAME = 'competition_id'
      AND REFERENCED_TABLE_NAME IS NOT NULL
    LIMIT 1;
    IF v_fk IS NOT NULL THEN
        SET @drop_sql = CONCAT('ALTER TABLE training_weeks DROP FOREIGN KEY `', v_fk, '`');
        PREPARE drop_stmt FROM @drop_sql;
        EXECUTE drop_stmt;
        DEALLOCATE PREPARE drop_stmt;
    END IF;
END//
